<div class="es">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">El Costo del Suavizado Doble — Momentum Bruto vs. TSI Durante un Colapso</text>
  <line x1="60" y1="210" x2="650" y2="210" stroke="#3f3f46"/>
